import{_ as a,c as e,o,a as s}from"./app.1cfac776.js";const f=JSON.parse('{"title":"Importaci\xF3n y exportaci\xF3n de datos","description":"","frontmatter":{},"headers":[],"relativePath":"utilidades/importacion.md"}'),r={name:"utilidades/importacion.md"},t=s('<h1 id="importacion-y-exportacion-de-datos" tabindex="-1">Importaci\xF3n y exportaci\xF3n de datos <a class="header-anchor" href="#importacion-y-exportacion-de-datos" aria-hidden="true">#</a></h1><p>La importaci\xF3n de datos es fundamental para poder sincronizar datos de SIGAD a IesApp. En el men\xFA de utilidades encontramos varias posibilidades:</p><p><strong>Importaci\xF3n de alumnos y matr\xEDculas</strong></p><p>Los alumnos nuevos se pueden registrar a mano pero es m\xE1s pr\xE1ctico en la mayor\xEDa de los casos importarlos de los datos que nos brinda SIGAD. Los alumnos nuevos se incorporan al sistema y las matr\xEDculas nuevas se dan de alta en el sistema.</p><p><strong>Importaci\xF3n de credenciales SIGAD</strong></p><p>La lista de usuarios de SIGAD puede ser descargada en formato excel. Se trata del nombre de usuario y el correo asociado. Estas credenciales se pueden importar para que est\xE9n disponibles en el perfil del alumno y evitar bastantes consultas a tutores y jefatura.</p><p><strong>Importaci\xF3n de horarios</strong></p><p>Los horarios no se registran manualmente en IesApp, se importan usando el mismo fichero XML que se usa para pasarlos de Pe\xF1alara a SIGAD.</p><p><strong>Exportaci\xF3n de alumnos</strong></p><p>Se puede exportar una excel con los datos de todos los alumnos y la informaci\xF3n b\xE1sica de su matr\xEDcula.</p><p><strong>Exportaci\xF3n de fotos de profesores y alumnos</strong></p><p>Se puede exportar en fichero zip todas las fotos de los alumnos y profesores para la elaboraci\xF3n de orlas y anuarios.</p><p><strong>Otros</strong></p><p>Adem\xE1s, existen otros procesos de importaci\xF3n ya citados en otras partes de esta documentaci\xF3n: movimientos bancarios, incidencias disciplinarias.</p>',14),n=[t];function i(p,d,c,l,m,u){return o(),e("div",null,n)}const g=a(r,[["render",i]]);export{f as __pageData,g as default};
